INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00320', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '弈秋，通國之善弈者也。使弈秋誨二人弈，其一人專心致志，惟弈秋之為 聽。一人雖聽之，一心以為有鴻鵠將至，思援弓繳而射之，雖與之俱學， 弗若之矣。（《孟子．告子上》）依據上文文意，學習態度應該是：', '["足不出戶", "目不窺園", "耳不暇聽", "衣不解帶"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00321', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '《禮記．學記》：「三年視敬業樂群」下列何者與本文的意旨最接近？', '["博學篤志，切問近思", "己所不欲，勿施於人", "以文會友，以友輔仁", "知類通達，強立不反"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00322', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '荀子曰：「君子居必擇鄉，遊必就士，所以防邪僻而近中正也。」下列何 者與本文的意旨最相近？', '["螣蛇無足而飛，梧鼠五技而窮", "里仁為美，擇不處仁，焉得智", "假輿馬者，非利足也，而致千里", "強自取柱，柔自取束；邪穢在身，怨之所構"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00323', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '善學者，師逸而功倍，又從而庸之；不善學者，師勤而功半，又從而怨之。 （《禮記．學記》）關於本文的解讀，最適合的選項是：', '["學生能掌握學習方法，老師便教得輕鬆", "學習成果的好壞，取決於教師的勤與逸", "有效的教學方法，能快速提升學習成果", "不懂得學習的人，總是抱怨老師留一手"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00324', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「我給自己機會；我是一粒種籽，我也不僅是一粒——我是一棵樹；我種 我自己。」上文旨在強調：', '["播種須把握機會，錯過機會無法發芽", "珍惜時光，一棵樹無法回到種籽狀態", "單薄一粒種籽，成為大樹後機會才多", "必須播種才有機會，機會是自己給的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00325', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「不管是出現在小說、電影、漫畫還是廣告片裡，唯有故事能夠讓我們瞬 間進入『另一個人生』。人生在世，大部分的人都不會對自己的處境完全 滿意，卻也沒有辦法可以改變。如果不考慮投胎的話，『聽故事』是唯一 可以讓你暫時逃離當下人生的解決方案。這種遁逃，成就了人類最古老也 最根深柢固的娛樂形式。」依據上文，下列敘述最正確的是：', '["故事提供令人滿意的人生方案", "故事可以讓人反省自己的人生", "故事的世界中充滿著人生智慧", "故事可讓人感受不一樣的人生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00326', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「鐵鎚原是用來敲東西的，現在拿來炒菜，當然炒不好，而世人居然還要 指著鐵鎚痛罵：『要你有什麼用？』」下列敘述，最能說明此段文字主旨 的是：', '["無用之用，是為大用", "指出缺失，才能精益求精", "經過錘鍊，才能夠出類拔萃", "器物是否有用，當視其使用目的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00327', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「小學的時候，可能仰慕某一位老師或明星；長大一點，可能認定某某作 家是偶像。我們學習這些人的典範，然後二十五歲以後，是我們要開始自 己創造。如果一輩子都在學別人，我們就不可能成為一個典範；對我們來 說，只有在自己能夠成為一個典範時，過去的偶像才發揮出真正的正面作 用。」根據上文，偶像對自己的正面影響是：', '["隨時跟得上時代潮流", "使表現獲得眾人崇拜", "更懂得發揮自身特色", "有明確可遵循的目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00328', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「對群島國來說，每一座島嶼或島礁，儘管面積不大或無人居住，但每個 撒佈在我們海域裡的島或礁，都比珍珠還要珍貴。以因果關係來說，這些 『島或礁』是因，『我們的海域』是果；以幾何概念來說，這些珍珠是點， 這些點所撐張的海域範圍是面。」根據上文，島嶼或島礁的珍貴處在於：', '["延伸的海權", "稀有的礦產", "擁有的陸地面積", "蘊藏的海洋資源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00329', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「問題，是所有創意的起點。一般都說需求是創造之母，可是汽車大王 亨利．福特曾說：『去問消費者，你需要什麼？他們會說，我要一輛更好 的馬車，因為他們不知道會有汽車。』人不一定知道自己的需求，他如果 知道，創意就開始了。問題會引發創造的動機與動力，所以問題才是創造 之父。 世界上有兩種人，一種可以看出問題，一種看不出。前者又分兩種，想辦 法解決和只會抱怨。解決問題像爬階梯，每解決一個問題，就爬上一層階 梯。每上一個階梯會讓你看得更廣、更遠，看出新的問題。用問題的電波 向四周探索，會發現一大堆問題等著解決。不論問題大小，都需要創意去 解決，小創意也有大影響。」根據上文，下列選項最符合文意的是：', '["問題與創意不相干", "在抱怨中必有創意", "創意來自解決問題", "創意來自實際需求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
